module mg_01614(input clk, input ce, input reset,input odd_cycle,input sprite_trigger,input dmc_trigger,input cpu_read,input [7:0] data_from_cpu,input [7:0] data_from_ram,input [15:0] dmc_dma_addr,output [15:0] aout,output aout_enable,output read,output [7:0] data_to_ram,output dmc_ack,output pause_cpu);
reg dmc_state; 
  reg [1:0] spr_state; 
  reg [7:0] sprite_dma_lastval; 
  reg [15:0] sprite_dma_addr; 
  wire [8:0] new_sprite_dma_addr = sprite_dma_addr[7:0] + 8'h01; 
  always @(posedge clk) if (reset) begin 
  dmc_state <= 0; 
  spr_state <= 0; 
  sprite_dma_lastval <= 0; 
  sprite_dma_addr <= 0; 
  end else if (ce) begin 
  if (dmc_state == 0 && dmc_trigger && cpu_read && !odd_cycle) dmc_state <= 1; 
  if (dmc_state == 1 && !odd_cycle) dmc_state <= 0; 
  if (sprite_trigger) begin sprite_dma_addr <= {data_from_cpu, 8'h00}; spr_state <= 1; end 
  if (spr_state == 1 && cpu_read && odd_cycle) spr_state <= 3; 
  if (spr_state[1] && !odd_cycle && dmc_state == 1) spr_state <= 1; 
  if (spr_state[1] && odd_cycle) sprite_dma_addr[7:0] <= new_sprite_dma_addr[7:0]; 
  if (spr_state[1] && odd_cycle && new_sprite_dma_addr[8]) spr_state <= 0; 
  if (spr_state[1]) sprite_dma_lastval <= data_from_ram; 
  end 
  assign pause_cpu = (spr_state[0] || dmc_trigger) && cpu_read; 
  assign dmc_ack = (dmc_state == 1 && !odd_cycle); 
  assign aout_enable = dmc_ack || spr_state[1]; 
  assign read = !odd_cycle; 
  assign data_to_ram = sprite_dma_lastval; 
  assign aout = dmc_ack ? dmc_dma_addr : !odd_cycle ? sprite_dma_addr : 16'h2004; 
 endmodule

