module rtlpp_06211(B, X, Clk, Rst);

input B;
output reg X;
input Clk, Rst;

parameter S_Off = 2'b00, S_On1 = 2'b01, S_On2 = 2'b10, S_On3 = 2'b11;

reg [1:0] State, StateNext; 

always @(State or B) begin 
  case (State)
    S_Off: begin
      X <= 0; 
      if (B == 0) 
        StateNext <= S_Off;
      else
        StateNext <= S_On1;
