module autovcoder_091747 (
    input [4:0] EXE_original_write_reg_number,
    input [31:0] EXE_pc_plus_4,
    input [31:0] EXE_q1,
    input [31:0] EXE_q2,
    input [31:0] EXE_imm,
    input [31:0] EXE_shift_amount,
    input [3:0] EXE_aluc,
