);
  // EXE 级

  wire [31:0] alua, alub, alu_res, is_zero;
  mux2x32 alu_a (
      EXE_q1,
      EXE_shift_amount,
      EXE_shift,
      alua
  );
  mux2x32 alu_b (
      EXE_q2,
      EXE_imm,
      EXE_aluimm,
