  );
  alu al_unit (
      .a(alua),
      .b(alub),
      .aluc(EXE_aluc),
      .res(alu_res),
      .is_zero(is_zero)
  );
  // 进行 ALU 组合运算

  // wire [31: 0] EXE_pc_plus_8;
