module origen_127811 (
    input wire clk_vga,
    output wire hs,
    output wire vs,
    output wire hc_visible,
    output wire vc_visible
);

    // Horizontal timing parameters
    localparam H_VISIBLE = 1024;
    localparam H_FRONT_PORCH = 24;
    localparam H_SYNC_PULSE = 96;
    localparam H_BACK_PORCH = 136;
    localparam H_TOTAL = H_VISIBLE + H_FRONT_PORCH + H_SYNC_PULSE + H_BACK_PORCH;

    // Vertical timing parameters
    localparam V_VISIBLE = 768;
    localparam V_FRONT_PORCH = 16;
    localparam V_SYNC_PULSE = 2;
    localparam V_BACK_PORCH = 6;
    localparam V_TOTAL = V_VISIBLE + V_FRONT_PORCH + V_SYNC_PULSE + V_BACK_PORCH;

    // Counters for horizontal and vertical positions
    reg [10:0] h_count;
    reg [9:0] v_count;

    // Horizontal counter
    always @(posedge clk_vga) begin
        if (h_count == H_TOTAL - 1)
            h_count <= 0;
        else
            h_count <= h_count + 1;
    end

    // Vertical counter
    always @(posedge clk_vga) begin
        if (h_count == H_TOTAL - 1) begin
            if (v_count == V_TOTAL - 1)
                v_count <= 0;
            else
                v_count <= v_count + 1;
        end
    end

    // Horizontal sync signal
    assign hs = (h_count >= (H_VISIBLE + H_FRONT_PORCH) &&
                 h_count < (H_VISIBLE + H_FRONT_PORCH + H_SYNC_PULSE)) ? 1'b0 : 1'b1;

    // Vertical sync signal
    assign vs = (v_count >= (V_VISIBLE + V_FRONT_PORCH) &&
                 v_count < (V_VISIBLE + V_FRONT_PORCH + V_SYNC_PULSE)) ? 1'b0 : 1'b1;

    // Horizontal visible area
    assign hc_visible = (h_count < H_VISIBLE) ? 1'b1 : 1'b0;

    // Vertical visible area
    assign vc_visible = (v_count < V_VISIBLE) ? 1'b1 : 1'b0;

endmodule

