    assign XLXN_2_2 = XLXN_13 & XLXN_24;
    assign C_OUT_3 = RST & XLXN_1_2;
    assign XLXN_25 = RST & XLXN_2_1;

    // Third half adder instance logic within Twos_Complement
    assign XLXN_1_3 = XLXN_14 ^ XLXN_23;
    assign XLXN_2_3 = XLXN_14 & XLXN_23;
    assign C_OUT_2 = RST & XLXN_1_3;
    assign XLXN_24 = RST & XLXN_2_2;

    // Fourth half adder instance logic within Twos_Complement
    assign XLXN_1_4 = XLXN_15 ^ XLXN_30;
    assign XLXN_2_4 = XLXN_15 & XLXN_30;
    assign C_OUT_1 = RST & XLXN_1_4;
    assign XLXN_23 = RST & XLXN_2_3;

