    chipselect,
    clk,
    in_port,
    reset_n,
    write_n,
    writedata,
    irq,
    out_port,
    readdata
);

  output          irq;
  output [31:0]   out_port;
  output [31:0]   readdata;
  input  [2:0]    address;
  input           chipselect;
  input           clk;
  input  [31:0]   in_port;
  input           reset_n;
  input           write_n;
  input  [31:0]   writedata;

  wire            clk_en;
  wire  [31:0]    data_in;
  reg   [31:0]    data_out;
  reg   [31:0]    irq_mask;
  wire  [31:0]    read_mux_out;
  reg   [31:0]    readdata;
  wire            wr_strobe;

  assign clk_en = 1;

  assign read_mux_out = ({32{(address == 0)}} & data_in) |
                        ({32{(address == 2)}} & irq_mask);

  always @(posedge clk or negedge reset_n) begin
    if (~reset_n)
      readdata <= 0;
    else if (clk_en)
      readdata <= read_mux_out;
  end

  assign wr_strobe = chipselect && ~write_n;

  always @(posedge clk or negedge reset_n) begin
    if (~reset_n)
      data_out <= 0;
    else if (clk_en) begin
      if (wr_strobe) begin
        case (address)
          5: data_out <= data_out & ~writedata[31:0];
          4: data_out <= data_out | writedata[31:0];
          0: data_out <= writedata[31:0];
