module rtlpp_10780(clk, nrst, rx_data, rx_busy, rx_done, rx_err, rxd);

parameter CLK_HZ = 200_000_000;
parameter BAUD = 9600;
parameter BAUD_DIVISOR_2 = CLK_HZ / BAUD / 2;

input wire clk;
input wire nrst;

output reg [7:0] rx_data = 0;
reg rx_data_9th_bit = 0;	

output reg rx_busy = 0;
output wire rx_done;		
output wire rx_err;
input wire rxd;

reg s_rxd = 0;
reg s_rxd_delay = 0;  // StaticDelay equivalent embedded

// Equivalent StaticDelay behavior
always @ (posedge clk) begin
    if (~nrst) begin
        s_rxd <= 0;
        s_rxd_delay <= 0;
    end else begin
        s_rxd <= rxd;
        s_rxd_delay <= s_rxd;
    end
end

wire delayed_rxd = s_rxd_delay;

reg rxd_prev = 0;
always @ (posedge clk) begin
    if (~nrst) begin
        rxd_prev <= 0;
    end else begin
        rxd_prev <= delayed_rxd;
    end
end
wire start_bit_strobe = ~delayed_rxd & rxd_prev;

reg [15:0] rx_sample_cntr = (BAUD_DIVISOR_2 - 1);
wire rx_do_sample = (rx_sample_cntr[15:0] == 0);
always @ (posedge clk) begin
    if (~nrst) begin
        rx_busy <= 0;
    end else begin
        if (~rx_busy) begin
            if (start_bit_strobe) begin
                rx_sample_cntr[15:0] <= (BAUD_DIVISOR_2 * 3 - 1);		
                {rx_data[7:0], rx_data_9th_bit} <= 9'b100000000;
                rx_busy <= 1;
            end 
        end else begin
            if (rx_sample_cntr[15:0] == 0) begin
                rx_sample_cntr[15:0] <= (BAUD_DIVISOR_2 * 2 - 1);	
            end else begin
                rx_sample_cntr[15:0] <= rx_sample_cntr[15:0] - 1;	
            end

            if (rx_do_sample) begin
                if (rx_data_9th_bit == 1) begin
                    rx_busy <= 0;		
                end else begin
                    {rx_data[7:0], rx_data_9th_bit} <= {delayed_rxd, rx_data[7:0]};
                end	
            end 
        end	
    end 
end

assign
    rx_done = rx_data_9th_bit && rx_do_sample && delayed_rxd,		
    rx_err = rx_data_9th_bit && rx_do_sample && ~delayed_rxd;

endmodule

