module autovcoder_090035 (
    SW,
    LEDR,
    HEX3,
    HEX2,
    HEX1,
    HEX0
);
  input [8:0] SW;
  output [4:0] LEDR;
  output [6:0] HEX3, HEX2, HEX1, HEX0;
  wire s1, s2;

  b2d_7seg C0 (
      SW[3:0],
      HEX3
  );
  b2d_7seg C1 (
      SW[7:4],
      HEX2
  );

  wire c1, c2, c3;
  wire [4:0] S;

  fulladder A0 (
      SW[0],
      SW[4],
      SW[8],
      S[0],
      c1
  );
  fulladder A1 (
      SW[1],
      SW[5],
      c1,
      S[1],
      c2
  );
  fulladder A2 (
      SW[2],
      SW[6],
      c2,
      S[2],
      c3
  );
  fulladder A3 (
      SW[3],
      SW[7],
      c3,
      S[3],
      S[4]
  );

  assign LEDR[4:0] = S[4:0];

  wire z, en;
  wire [3:0] A, M;

  comparator9 C2 (
      S[4:0],
      z
  );
  circuitA A4 (
      S[3:0],
      A
  );
  mux_4bit_2to1 M0 (
      z,
      S[3:0],
      A,
      M
  );
  comparator19 comp19 (
      S[4:0],
      en
  );
  circuitB B0 (
      en,
      z,
      HEX1
  );
  b2d_7seg0 S0 (
      ~en,
      M,
      HEX0
  );

endmodule

