module autovcoder_035663 (
    clk_top,
    rst,
    SystemEnd,
    SystemStart,
    PHYInitEnd,
    NumbFrameReturned,
    DistFrameReturned,
    DelayFrameReturned,
    DelayDistFrameReturned,
    ConfigEnd,
    DataFrameGo,
    StateIdle,
    StateNumb,
    StateDist,
    StateDelay,
    StateDelayDist,
    StateData,
    StateWait
);

  input       clk_top;   // I think this should be the TX clock since it control the start of transmitting frames
  input rst;
  input SystemEnd;
  input SystemStart;
  input PHYInitEnd;
  input NumbFrameReturned;
  input DistFrameReturned;
  input DelayFrameReturned;
  input DelayDistFrameReturned;
  input ConfigEnd;
  input DataFrameGo;

  output StateIdle;
  output StateNumb;
  output StateDist;
  output StateDelay;
  output StateDelayDist;
  output StateData;
  output StateWait;

  reg  StateIdle;
  reg  StateNumb;
  reg  StateDist;
  reg  StateDelay;
  reg  StateDelayDist;
  reg  StateData;
  reg  StateWait;

  wire StartIdle;
  wire StartNumb;
  wire StartDist;
  wire StartDelay;
  wire StartDelayDist;
  wire StartData;
  wire StartWait;

  assign StartIdle      = SystemEnd;

  assign StartNumb      = StateIdle & SystemStart & PHYInitEnd;

  assign StartDist      = StateWait & NumbFrameReturned;

  assign StartDelay     = StateWait & DistFrameReturned;

  assign StartDelayDist = StateWait & DelayFrameReturned;

  assign StartData      = StateWait & (DelayDistFrameReturned | ConfigEnd & DataFrameGo);

  assign StartWait      = StateNumb | StateDist | StateDelay | StateDelayDist | StateData;


  always @(posedge clk_top or posedge rst) begin
    if (rst) begin
      StateIdle      <= 1'b1;
      StateNumb      <= 1'b0;
      StateDist      <= 1'b0;
      StateDelay     <= 1'b0;
      StateDelayDist <= 1'b0;
      StateData      <= 1'b0;
      StateWait      <= 1'b0;
    end else begin

      if (StartNumb) StateIdle <= 1'b0;
      else if (StartIdle) StateIdle <= 1'b1;

      if (StartWait | StartIdle) StateNumb <= 1'b0;
      else if (StartNumb) StateNumb <= 1'b1;

      if (StartWait | StartIdle) StateDist <= 1'b0;
      else if (StartDist) StateDist <= 1'b1;

      if (StartWait | StartIdle) StateDelay <= 1'b0;
      else if (StartDelay) StateDelay <= 1'b1;

      if (StartWait | StartIdle) StateDelayDist <= 1'b0;
      else if (StartDelayDist) StateDelayDist <= 1'b1;

      if (StartWait | StartIdle) StateData <= 1'b0;
      else if (StartData) StateData <= 1'b1;

      if (StartIdle | StartDist | StartDelay | StartDelayDist | StartData) StateWait <= 1'b0;
      else if (StartWait) StateWait <= 1'b1;

    end
  end

endmodule

