module autovcoder_002702 (
    input wire    sclk,
    input wire    rst,
    //user read ports
    input wire    rd_cmd_start,
    input wire  [2:0] rd_cmd_instr,
    input wire  [6:0] rd_cmd_bl,
    input wire  [27:0] rd_cmd_addr,
    output wire  [127:0] rd_data_128bit,
    output wire    rd_data_valid,
    output wire    rd_end,
    //ddr3 ipcore ports
    input wire  [127:0] app_rd_data,
    input wire    app_rd_data_valid,
    output wire    app_en,
    input wire    app_rdy,
    output wire  [27:0] app_addr,
    output wire  [2:0] app_cmd

);

  reg [2:0] cmd_instr;
  reg [6:0] cmd_bl;
  reg app_en_r;
  reg [6:0] cmd_cnt;
  reg [27:0] app_addr_r;
  reg [6:0] data_cnt;
  reg rd_end_r;

  assign rd_data_128bit = app_rd_data;
  assign rd_data_valid = app_rd_data_valid;
  assign app_en = app_en_r;
  assign app_addr = app_addr_r;
  assign rd_end = rd_end_r;

  always @(posedge sclk) begin
    if (rst == 1'b1) begin
      cmd_instr <= 'd0;
      cmd_bl <= 'd0;
    end else if (rd_cmd_start == 1'b1) begin
      cmd_instr <= rd_cmd_instr;
      cmd_bl <= rd_cmd_bl;
    end
  end

  assign app_cmd = cmd_instr;


  always @(posedge sclk) begin
    if (rst == 1'b1) begin
      cmd_cnt <= 'd0;
    end else if (app_en_r == 1'b1 && app_rdy == 1'b1 && cmd_cnt == (cmd_bl - 1)) begin
      cmd_cnt <= 'd0;
    end else if (app_en_r == 1'b1 && app_rdy == 1'b1) begin
      cmd_cnt <= cmd_cnt + 1'b1;
    end
  end

  always @(posedge sclk) begin
    if (rst == 1'b1) begin
      app_en_r <= 1'b0;
    end else if (app_en_r == 1'b1 && app_rdy == 1'b1 && cmd_cnt == (cmd_bl - 1)) begin
      app_en_r <= 1'b0;
    end else if (rd_cmd_start == 1'b1) begin
      app_en_r <= 1'b1;
    end
  end

  always @(posedge sclk) begin
    if (rst == 1'b1) begin
      app_addr_r <= 'd0;
    end else if (rd_end_r == 1'b1) begin
      app_addr_r <= 'd0;
    end else if (rd_cmd_start == 1'b1) begin
      app_addr_r <= rd_cmd_addr;
    end else if (app_en_r == 1'b1 && app_rdy == 1'b1) begin
      app_addr_r <= app_addr_r + 'd8;
    end
  end


  always @(posedge sclk) begin
    if (rst == 1'b1) begin
      data_cnt <= 'd0;
    end else if (data_cnt == (cmd_bl - 1) && app_rd_data_valid == 1'b1) begin
      data_cnt <= 'd0;
    end else if (app_rd_data_valid == 1'b1) begin
      data_cnt <= data_cnt + 1'b1;
    end
  end

  always @(posedge sclk) begin
    if (rst == 1'b1) begin
      rd_end_r <= 'd0;
    end else if (data_cnt == (cmd_bl - 1) && app_rd_data_valid == 1'b1) begin
      rd_end_r <= 1'b1;
    end else begin
      rd_end_r <= 1'b0;
    end
  end




endmodule

