module autovcoder_077010 (
    out0,
    a,
    b
);
  output [7:0] out0;
  input [7:0] a;
  input [7:0] b;

  wire \<const0> ;
  wire [7:0] a;
  wire [7:0] b;
  wire [7:0] out0;
  wire [7:0] p;

  GND GND (.G(\<const0> ));
  (* BOX_TYPE = "PRIMITIVE" *)
  CARRY8 #(
      .CARRY_TYPE("SINGLE_CY8")
  ) carry0 (
      .CI(\<const0> ),
      .CI_TOP(\<const0> ),
      .DI(a),
      .O(out0),
      .S(p)
  );
  (* BOX_TYPE = "PRIMITIVE" *)
  LUT2 #(
      .INIT(4'h6)
  ) l0 (
      .I0(a[0]),
      .I1(b[0]),
      .O (p[0])
  );
  (* BOX_TYPE = "PRIMITIVE" *)
  LUT2 #(
      .INIT(4'h6)
  ) l1 (
      .I0(a[1]),
      .I1(b[1]),
      .O (p[1])
  );
  (* BOX_TYPE = "PRIMITIVE" *)
  LUT2 #(
