module autovcoder_026989 (
    input  [3:0] I0,
    input  [3:0] I1,
    output [3:0] O
);
  wire LUT2_inst0_O;
  wire MUXCY_inst0_O;
  wire XORCY_inst0_O;
  wire LUT2_inst1_O;
  wire MUXCY_inst1_O;
  wire XORCY_inst1_O;
  wire LUT2_inst2_O;
  wire MUXCY_inst2_O;
  wire XORCY_inst2_O;
  wire LUT2_inst3_O;
  wire MUXCY_inst3_O;
  wire XORCY_inst3_O;
  LUT2 #(
      .INIT(4'h6)
  ) LUT2_inst0 (
      .I0(I0[0]),
      .I1(I1[0]),
      .O (LUT2_inst0_O)
  );
  MUXCY MUXCY_inst0 (
      .DI(I0[0]),
      .CI(1'b0),
      .S (LUT2_inst0_O),
      .O (MUXCY_inst0_O)
  );
  XORCY XORCY_inst0 (
      .LI(LUT2_inst0_O),
      .CI(1'b0),
      .O (XORCY_inst0_O)
  );
  LUT2 #(
      .INIT(4'h6)
  ) LUT2_inst1 (
