      .I1(I1[1]),
      .O (LUT2_inst1_O)
  );
  MUXCY MUXCY_inst1 (
      .DI(I0[1]),
      .CI(MUXCY_inst0_O),
      .S (LUT2_inst1_O),
      .O (MUXCY_inst1_O)
  );
  XORCY XORCY_inst1 (
      .LI(LUT2_inst1_O),
      .CI(MUXCY_inst0_O),
      .O (XORCY_inst1_O)
  );
  LUT2 #(
      .INIT(4'h6)
  ) LUT2_inst2 (
      .I0(I0[2]),
