module autovcoder_067738 (  //	Host Side
    iCLK,
    iRST_N,
    VCM_DATA,
    ENABLE,
    END,

    //	I2C Side
    I2C_SCLK,
    I2C_SDAT
);

  //	Host Side
  input iCLK;
  input iRST_N;
  input [15:0] VCM_DATA;
  input ENABLE;
  output END;

  //	I2C Side
  inout I2C_SCLK;
  inout I2C_SDAT;



  //	Internal Registers/Wires
  reg  [15:0] mI2C_CLK_DIV;
  reg  [23:0] mI2C_DATA;
  reg         mI2C_CTRL_CLK;
  reg         mI2C_GO;
  wire        mI2C_END;
  wire        mI2C_ACK;
  reg  [ 3:0] mSetup_ST;
  wire        END;


  /////////////////////////////////////////////////////////////////////

  //	Clock Setting
  parameter CLK_Freq = 50_000_000;  //	 50 MHz
  parameter I2C_Freq = 100_000;  //	100 KHz

  /////////////////////	I2C Control Clock	////////////////////////
  always @(posedge iCLK or negedge iRST_N) begin
    if (!iRST_N) begin
      mI2C_CTRL_CLK <= 0;
      mI2C_CLK_DIV  <= 0;
    end else begin
      if (mI2C_CLK_DIV < (CLK_Freq / I2C_Freq)) mI2C_CLK_DIV <= mI2C_CLK_DIV + 1;
      else begin
        mI2C_CLK_DIV  <= 0;
        mI2C_CTRL_CLK <= ~mI2C_CTRL_CLK;
      end
    end
  end
  ////////////////////////////////////////////////////////////////////
  I2C_VCM_Controller u0 (
      .CLOCK   (mI2C_CTRL_CLK),  //	Controller Work Clock
      .I2C_SCLK(I2C_SCLK),       //	I2C CLOCK
      .I2C_SDAT(I2C_SDAT),       //	I2C DATA
      .I2C_DATA(mI2C_DATA),      //	DATA:[SLAVE_ADDR,SUB_ADDR,DATA]
      .GO      (mI2C_GO),        //	GO transfor
      .END     (mI2C_END),       //	END transfor 
      .ACK     (mI2C_ACK),       //	ACK
      .RESET   (iRST_N)
  );
  ////////////////////////////////////////////////////////////////////
  //////////////////////	Config Control	////////////////////////////
  reg f_trig;
  reg f_trig_clear;

  always @(posedge mI2C_CTRL_CLK or negedge iRST_N) begin
    if (!iRST_N) f_trig <= 1'b1;
    else if (f_trig_clear) f_trig <= 1'b0;
  end


  always @(posedge mI2C_CTRL_CLK) begin
    case (mSetup_ST)
      0: begin
        mI2C_DATA <= {8'h18, VCM_DATA};  // 0x18 is VCM149C's I2C slave Addr
        if (ENABLE) begin
          mSetup_ST <= 1;
          mI2C_GO   <= 1;
        end else begin
          mSetup_ST <= 0;
          mI2C_GO   <= 0;
        end
        f_trig_clear <= 1'b0;
      end
      1: begin
        if (mI2C_END) begin
          if (!mI2C_ACK) mSetup_ST <= 2;
          else mSetup_ST <= 0;
          mI2C_GO <= 0;
        end
        f_trig_clear <= 1'b0;
      end
      2: begin
        if (f_trig) begin
          mSetup_ST <= 0;
          f_trig_clear <= 1'b1;
        end else begin
          mSetup_ST <= 2;
          f_trig_clear <= 1'b0;
        end
      end
      default: mSetup_ST <= 0;
    endcase
  end


  assign END = (mSetup_ST == 2);

endmodule

