module rtlpp_06673 (
              address,
              chipselect,
              clk,
              in_port,
              reset_n,
              write_n,
              writedata,
              irq,
              readdata
           );

  output irq;
  output [ 3: 0] readdata;
  input [ 1: 0] address;
  input chipselect;
  input clk;
  input [ 3: 0] in_port;
  input reset_n;
  input write_n;
  input [ 3: 0] writedata;

  wire clk_en;
  reg [ 3: 0] d1_data_in;
  reg [ 3: 0] d2_data_in;
  wire [ 3: 0] data_in;
  reg [ 3: 0] edge_capture;
  wire edge_capture_wr_strobe;
  wire [ 3: 0] edge_detect;
  reg [ 3: 0] irq_mask;
  wire [ 3: 0] read_mux_out;
  reg [ 3: 0] readdata;

  assign clk_en = 1;

  assign read_mux_out = ({4 {(address == 2'b00)}} & data_in) |
                        ({4 {(address == 2'b10)}} & irq_mask) |
                        ({4 {(address == 2'b11)}} & edge_capture);

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 1'b0)
        readdata <= 4'b0000;
    else if (clk_en)
        readdata <= read_mux_out;
  end

  assign data_in = in_port;

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 1'b0)
        irq_mask <= 4'b0000;
    else if (chipselect && ~write_n && (address == 2'b10))
        irq_mask <= writedata[3:0];
  end

  assign irq = |(edge_capture & irq_mask);
  assign edge_capture_wr_strobe = chipselect && ~write_n && (address == 2'b11);

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 1'b0)
        edge_capture[0] <= 1'b0;
    else if (clk_en) begin
        if (edge_capture_wr_strobe)
            edge_capture[0] <= 1'b0;
        else if (edge_detect[0])
            edge_capture[0] <= 1'b1;
    end
  end

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 1'b0)
        edge_capture[1] <= 1'b0;
    else if (clk_en) begin
        if (edge_capture_wr_strobe)
            edge_capture[1] <= 1'b0;
