            Jump = 1'b0;
            Branch = 1'b0;
            MemRead = 1'b1;
            MemtoReg = 2'b01;
            ALUOp = 6'b100000;
            MemWrite = 1'b0;
            ALUSrc = 1'b1;
            RegWrite = 1'b1;
            JumpRegister = 1'b0;
        end
        6'b101011: begin // store instruction
            RegDst = 2'b00;
            Jump = 1'b0;
            Branch = 1'b0;
            MemRead = 1'b0;
            MemtoReg = 2'b00;
            ALUOp = 6'b100000;
            MemWrite = 1'b1;
            ALUSrc = 1'b1;
            RegWrite = 1'b0;
            JumpRegister = 1'b0;
        end
        6'b001000: begin // immediate instruction
            RegDst = 2'b00;
            Jump = 1'b0;
            Branch = 1'b0;
            MemRead = 1'b0;
            MemtoReg = 2'b00;
            ALUOp = 6'b100000;
            MemWrite = 1'b0;
            ALUSrc = 1'b1;
            RegWrite = 1'b1;
            JumpRegister = 1'b0;
        end
        6'b000100: begin // branch instruction
            RegDst = 2'b00;
            Jump = 1'b0;
            Branch = 1'b1;
            MemRead = 1'b0;
            MemtoReg = 2'b00;
            ALUOp = 6'b100010;
            MemWrite = 1'b0;
            ALUSrc = 1'b0;
            RegWrite = 1'b0;
            JumpRegister = 1'b0;
        end
        6'b000010: begin // jump instruction
            RegDst = 2'b00;
            Jump = 1'b1;
            Branch = 1'b0;
            MemRead = 1'b0;
            MemtoReg = 2'b10;
            ALUOp = 6'b000000;
            MemWrite = 1'b0;
            ALUSrc = 1'b0;
            RegWrite = 1'b0;
            JumpRegister = 1'b0;
        end
        default: begin
            RegDst = 2'b00;
            Jump = 1'b0;
            Branch = 1'b0;
            MemRead = 1'b0;
            MemtoReg = 2'b00;
            ALUOp = 6'b000000;
            MemWrite = 1'b0;
            ALUSrc = 1'b0;
            RegWrite = 1'b0;
            JumpRegister = 1'b0;
        end
    endcase
