  reg [FIFO_DEPTH_LOG2-1:0] fifo_head;
  reg [FIFO_DEPTH_LOG2-1:0] fifo_tail;
  reg fifo_full;
  reg fifo_empty;
  integer i;

  wire [FIFO_WIDTH-1:0] fifo_input;
  reg [FIFO_WIDTH-1:0] fifo_output;
  wire fifo_read;
  reg [FIFO_DEPTH_LOG2-1:0] fifo_used;

