    mt_wr_ptr = 0;
    mt_wr_en = 0;

    y1 = 0;
    y2 = 0;
    y3 = 0;
    y4 = 0;
    y5 = 0;

    mt_rd_a_ptr_next = mt_rd_a_ptr_reg;
    mt_rd_b_ptr_next = mt_rd_b_ptr_reg;

