module origen_030145(
    input wire clk,
    input wire clr,
    output reg [5:0] lights
);

    // State definitions
    parameter S0 = 3'b000, S1 = 3'b001, S2 = 3'b010,
              S3 = 3'b011, S4 = 3'b100, S5 = 3'b101;

    // Timing parameters
    parameter SEC5 = 25'd250000000; // 5 seconds at 50MHz clock
    parameter SEC1 = 25'd50000000;  // 1 second at 50MHz clock

    reg [2:0] state;
    reg [24:0] count;

    // Sequential block for state transitions and timing
    always @(posedge clk or posedge clr) begin
        if (clr) begin
            state <= S0;
            count <= 25'd0;
        end else begin
            case (state)
                S0: if (count == SEC5) begin state <= S1; count <= 25'd0; end
                    else count <= count + 1;
                S1: if (count == SEC1) begin state <= S2; count <= 25'd0; end
                    else count <= count + 1;
                S2: if (count == SEC1) begin state <= S3; count <= 25'd0; end
                    else count <= count + 1;
                S3: if (count == SEC5) begin state <= S4; count <= 25'd0; end
                    else count <= count + 1;
                S4: if (count == SEC1) begin state <= S5; count <= 25'd0; end
                    else count <= count + 1;
                S5: if (count == SEC1) begin state <= S0; count <= 25'd0; end
                    else count <= count + 1;
                default: state <= S0;
            endcase
        end
    end

    // Combinational block for light configuration
    always @(*) begin
        case (state)
            S0: lights = 6'b100001;
            S1: lights = 6'b100010;
            S2: lights = 6'b100100;
            S3: lights = 6'b001100;
            S4: lights = 6'b010100;
            S5: lights = 6'b100100;
            default: lights = 6'b100001;
        endcase
    end

endmodule

files.origen_134398.v:
module origen_134398 #(
    parameter WIDTH = 32
)(
    input wire clk,
    input wire rst,
    input wire [WIDTH-1:0] a,
    input wire [WIDTH-1:0] b,
    output reg [WIDTH-1:0] c
);

    localparam STAGES = $clog2(WIDTH);

    reg [WIDTH-1:0] a_reg [STAGES-1:0];
    reg [WIDTH-1:0] b_reg [STAGES-1:0];
    reg [2*WIDTH-1:0] partial_product [STAGES:0];

    integer i;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            for (i = 0; i < STAGES; i = i + 1) begin
                a_reg[i] <= 0;
                b_reg[i] <= 0;
            end
            for (i = 0; i <= STAGES; i = i + 1) begin
                partial_product[i] <= 0;
            end
        end else begin
            // First stage
            a_reg[0] <= a;
            b_reg[0] <= b;
            partial_product[0] <= 0;

            // Pipeline stages
            for (i = 1; i < STAGES; i = i + 1) begin
                a_reg[i] <= a_reg[i-1];
                b_reg[i] <= b_reg[i-1];
                partial_product[i] <= partial_product[i-1] + 
                    (a_reg[i-1][i-1] ? (b_reg[i-1] << (i-1)) : 0);
            end

            // Final stage
            partial_product[STAGES] <= partial_product[STAGES-1] + 
                (a_reg[STAGES-1][STAGES-1] ? (b_reg[STAGES-1] << (STAGES-1)) : 0);
        end
    end

    // Output assignment
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            c <= 0;
        end else begin
            c <= partial_product[STAGES][WIDTH-1:0];
        end
    end

endmodule

files.origen_004305.v:
module origen_004305 (
    input wire clk,
    input wire [11:0] avg_torque,
    input wire [4:0] cadence_vec,
    input wire [12:0] incline,
    input wire [1:0] setting,
    output reg [11:0] target_curr
);

    // Parameters
    parameter TORQUE_MIN = 12'd100;
    parameter INCLINE_MAX = 13'd4000;
    parameter INCLINE_MIN = -13'd4000;

    // Internal signals
    reg [12:0] incline_sat;
    reg [11:0] incline_factor, incline_lim;
    reg [7:0] cadence_factor;
    reg [11:0] torque_pos;
    reg [13:0] p1, p2;
    reg [25:0] assist_prod;

    // Incline processing
    always @(*) begin
        if (incline > INCLINE_MAX)
            incline_sat = INCLINE_MAX;
        else if (incline < INCLINE_MIN)
            incline_sat = INCLINE_MIN;
        else
            incline_sat = incline;

        incline_factor = (incline_sat >>> 1) + 12'd2048;
        incline_lim = (incline_factor > 12'd4095) ? 12'd4095 : incline_factor;
    end

    // Cadence processing
    always @(*) begin
        cadence_factor = {3'b0, cadence_vec} + 8'd32;
    end

    // Torque processing
    always @(*) begin
        torque_pos = (avg_torque > TORQUE_MIN) ? (avg_torque - TORQUE_MIN) : 12'd0;
    end

    // Assistance calculation pipeline
    always @(posedge clk) begin
        p1 <= {6'b0, setting} * cadence_factor;
        p2 <= p1 * incline_lim;
        assist_prod <= p2 * torque_pos;
    end

    // Target current determination
    always @(posedge clk) begin
        target_curr <= (assist_prod[25:12] > 12'hFFF) ? 12'hFFF : assist_prod[23:12];
    end

endmodule

