        .b(b[3:0]),
        .cin(cin),
        .sum(sum[3:0]),
        .cout(c[0])
    );

    carry_select_adder_4bit_slice csa1(
        .a(a[7:4]),
        .b(b[7:4]),
        .cin(c[0]),
        .sum(sum[7:4]),
        .cout(c[1])
    );

    carry_select_adder_4bit_slice csa2(
        .a(a[11:8]),
        .b(b[11:8]),
        .cin(c[1]),
        .sum(sum[11:8]),
        .cout(c[2])
    );

    carry_select_adder_4bit_slice csa3(
        .a(a[15:12]),
        .b(b[15:12]),
        .cin(c[2]),
        .sum(sum[15:12]),
        .cout(cout)
    );
