module rtlpp_10431(Res, OVF, A, B, clk, reset, enable);

    input [31:0] A, B;
    input clk, reset, enable;

    output reg [63:0] Res;
    output wire OVF;

    reg [31:0] A_in, B_in;
    wire [2047:0] normalizedWires;
    wire [63:0] secondStage_Res, secondStage_carry;
    wire [31:0] A_imm, B_imm;
    wire [63:0] Res_imm, finalRes;
    wire doNegateRes;

    assign A_imm = (A_in[31]) ? ~A_in + 1 : A_in; // Correct negation for Verilog
    assign B_imm = (B_in[31]) ? ~B_in + 1 : B_in; // Correct negation for Verilog

    assign finalRes = (Res_imm != 0 && doNegateRes) ? ~Res_imm + 1 : Res_imm; // Correct negation for Verilog
    assign doNegateRes = A_in[31] ^ B_in[31];

    multiplyAllBits firstStage(normalizedWires, A_imm, B_imm);
    addIntermedaiteWires secondStage(secondStage_Res, secondStage_carry, normalizedWires);
    addResWithCarry thirdStage(Res_imm, secondStage_Res, secondStage_carry);

    assign OVF = (Res[63] ^ A[31]) & (Res[63] ^ B[31]);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            A_in <= 0;
            B_in <= 0;
            Res <= 0;
        end else if (clk & enable) begin
            A_in <= A;
            B_in <= B;
        end else if (!clk) begin
            Res <= finalRes;
        end else begin
            A_in <= A_in;
            B_in <= B_in;
        end
    end
endmodule

