    if (reset_x == 1'b1) begin
      delayMatch_reg[0] <= 37'sh0000000000;
      delayMatch_reg[1] <= 37'sh0000000000;
      delayMatch_reg[2] <= 37'sh0000000000;
      delayMatch_reg[3] <= 37'sh0000000000;
