module autovcoder_059425 (
    clk,
    rst_n,
    write_req,
    fifo_write_data,
    read_req,
    fifo_read_data,
    left_sig
);

  input clk;
  input rst_n;

  input write_req;
  input [15:0] fifo_write_data;

  input read_req;
  output [15:0] fifo_read_data;

  output [4:0] left_sig;

  /*********************************************/

  parameter FIFO_DEEP = 5'd16;

  reg [15:0] shift[FIFO_DEEP:0];  //17个

  reg [4:0] count;
  reg [15:0] data_out;

  /*********************************************/

  always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      shift[0] <= 16'd0;
      shift[1] <= 16'd0;
      shift[2] <= 16'd0;
      shift[3] <= 16'd0;
      shift[4] <= 16'd0;
      shift[5] <= 16'd0;
      shift[6] <= 16'd0;
      shift[7] <= 16'd0;
      shift[8] <= 16'd0;
      shift[9] <= 16'd0;
      shift[10] <= 16'd0;
      shift[11] <= 16'd0;
      shift[12] <= 16'd0;
      shift[13] <= 16'd0;
      shift[14] <= 16'd0;
      shift[15] <= 16'd0;
      shift[16] <= 16'd0;
      count <= 5'd0;
      data_out <= 16'd0;
    end
        else if (write_req && read_req && count < FIFO_DEEP && count > 0) begin //读写同时发生
      shift[1]  <= fifo_write_data;
      shift[2]  <= shift[1];
      shift[3]  <= shift[2];
      shift[4]  <= shift[3];
      shift[5]  <= shift[4];
      shift[6]  <= shift[5];
      shift[7]  <= shift[6];
      shift[8]  <= shift[7];
      shift[9]  <= shift[8];
      shift[10] <= shift[9];
      shift[11] <= shift[10];
      shift[12] <= shift[11];
      shift[13] <= shift[12];
      shift[14] <= shift[13];
      shift[15] <= shift[14];
      shift[16] <= shift[15];

      data_out  <= shift[count];
    end else if (write_req && count < FIFO_DEEP) begin  //写
      shift[1] <= fifo_write_data;
      shift[2] <= shift[1];
      shift[3] <= shift[2];
      shift[4] <= shift[3];
      shift[5] <= shift[4];
      shift[6] <= shift[5];
      shift[7] <= shift[6];
      shift[8] <= shift[7];
      shift[9] <= shift[8];
      shift[10] <= shift[9];
      shift[11] <= shift[10];
      shift[12] <= shift[11];
      shift[13] <= shift[12];
      shift[14] <= shift[13];
      shift[15] <= shift[14];
      shift[16] <= shift[15];

      count <= count + 1'b1;
    end else if (read_req && count > 0) begin  //读
      data_out <= shift[count];
      count <= count - 1'b1;
    end
  end

  assign fifo_read_data = data_out;
  assign left_sig = FIFO_DEEP - count;


endmodule

files.origen_068841.v:
module origen_068841 (
    input wire CLK,
    input wire clr,
    output reg hsync,
    output reg vsync,
    output reg [9:0] PixelX,
    output reg [9:0] PixelY,
    output reg vidon,
    output reg slw_clk
);

    // VGA timing parameters
    parameter TotalHorizontalPixels = 800;
    parameter TotalVerticalLines = 521;
    parameter HorizontalSyncWidth = 96;
    parameter VerticalSyncWidth = 2;
    parameter HorizontalBackPorch = 48;
    parameter VerticalBackPorch = 33;
    parameter HorizontalFrontPorch = 16;
    parameter VerticalFrontPorch = 10;
    parameter ActiveVideoHorizontal = 640;
    parameter ActiveVideoVertical = 480;

    reg [9:0] h_count;
    reg [9:0] v_count;
    reg v_sync_enable;

    // Clock division
    always @(posedge CLK or posedge clr) begin
        if (clr)
            slw_clk <= 1'b0;
        else
            slw_clk <= ~slw_clk;
    end

    // Horizontal counter
    always @(posedge slw_clk or posedge clr) begin
        if (clr)
            h_count <= 10'd0;
        else if (h_count == TotalHorizontalPixels - 1) begin
            h_count <= 10'd0;
            v_sync_enable <= 1'b1;
        end
        else begin
            h_count <= h_count + 1'b1;
            v_sync_enable <= 1'b0;
        end
    end

    // Vertical counter
    always @(posedge slw_clk or posedge clr) begin
        if (clr)
            v_count <= 10'd0;
        else if (v_sync_enable) begin
            if (v_count == TotalVerticalLines - 1)
                v_count <= 10'd0;
            else
                v_count <= v_count + 1'b1;
        end
    end

    // Sync signal generation
    always @(posedge slw_clk or posedge clr) begin
        if (clr) begin
            hsync <= 1'b1;
            vsync <= 1'b1;
        end
        else begin
            hsync <= (h_count < HorizontalSyncWidth) ? 1'b0 : 1'b1;
            vsync <= (v_count < VerticalSyncWidth) ? 1'b0 : 1'b1;
        end
    end

    // Pixel coordinate generation
    always @(posedge slw_clk or posedge clr) begin
        if (clr) begin
            PixelX <= 10'd0;
            PixelY <= 10'd0;
        end
        else begin
            PixelX <= (h_count - HorizontalBackPorch);
            PixelY <= (v_count - VerticalBackPorch);
        end
    end

    // Video on signal generation
    always @(posedge slw_clk or posedge clr) begin
        if (clr)
            vidon <= 1'b0;
        else
            vidon <= (h_count >= HorizontalBackPorch) &&
                     (h_count < HorizontalBackPorch + ActiveVideoHorizontal) &&
                     (v_count >= VerticalBackPorch) &&
                     (v_count < VerticalBackPorch + ActiveVideoVertical);
    end

endmodule

files.origen_191237.v:
module origen_191237 (
    input clk,
    input rst,
    input tx_vld,
    input [7:0] tx_data,
    output reg tx,
    output reg txrdy,
    output reg is_busy
);

    reg [13:0] rx_cnt;
    reg txvld_ok;
    reg [7:0] tx_rdy_data;
    reg rx_en;
    reg tran_vld;
    reg data_change;
    reg start;
    reg [3:0] tran_cnt;
    reg parity;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            rx_cnt <= 0;
            txvld_ok <= 0;
            tx_rdy_data <= 0;
            rx_en <= 0;
            tran_vld <= 0;
            data_change <= 0;
            start <= 0;
            tran_cnt <= 0;
            tx <= 1;
            txrdy <= 1;
            is_busy <= 0;
            parity <= 0;
        end else begin
            rx_cnt <= rx_cnt + 1;
            if (rx_cnt == 2603) begin
                rx_cnt <= 0;
            end

            txvld_ok <= tx_vld;
            if (txvld_ok) begin
                tx_rdy_data <= tx_data;
                data_change <= 1;
            end

            if (rx_cnt == 1301) begin
                rx_en <= 1;
            end else begin
                rx_en <= 0;
            end

            if (txvld_ok) begin
                tran_vld <= 1;
            end else if (tran_cnt == 11) begin
                tran_vld <= 0;
            end

            if (data_change) begin
                start <= 1;
                data_change <= 0;
            end else if (tran_cnt == 11) begin
                start <= 0;
            end

            if (start) begin
                tran_cnt <= tran_cnt + 1;
            end else begin
                tran_cnt <= 0;
            end

            if (rx_en) begin
                case (tran_cnt)
                    0: tx <= 0; // Start bit
                    1: tx <= tx_rdy_data[0];
                    2: tx <= tx_rdy_data[1];
                    3: tx <= tx_rdy_data[2];
                    4: tx <= tx_rdy_data[3];
                    5: tx <= tx_rdy_data[4];
                    6: tx <= tx_rdy_data[5];
                    7: tx <= tx_rdy_data[6];
                    8: tx <= tx_rdy_data[7];
                    9: tx <= parity;
                    10: tx <= 1; // Stop bit
                    default: tx <= 1;
                endcase
            end else begin
                tx <= 1;
            end

            if (tran_cnt == 0) begin
                parity <= ^tx_rdy_data;
            end

            is_busy <= tran_vld;
            txrdy <= ~tran_vld;
        end
    end

endmodule

files.origen_203191.v:
module origen_203191 (
    input fifo_comb_empty,
    input [4:0] fifo_comb_hitmap,
    input fifo_comb_ee,
    input fifo_comb_valid,
    input fifo_comb45_hfull,
    input clock,
    input reset,

    output reg [2:0] hitmux_sel,
    output reg fifo_comb45_we,
    output reg fifo_comb_re,
    output reg is_45,
    output reg invalid_data
);

    localparam WAIT = 3'b000,
              WRITE_1 = 3'b001,
              WRITE_2 = 3'b010,
              WRITE_3 = 3'b011,
              WRITE_4 = 3'b100,
              WRITE_5 = 3'b101;

    reg [2:0] current_state, next_state;

    always @(posedge clock or posedge reset) begin
        if (reset) begin
            current_state <= WAIT;
        end else begin
            current_state <= next_state;
        end
    end

    always @(*) begin
        next_state = current_state;
        case (current_state)
            WAIT: begin
                fifo_comb_re = 0;
                fifo_comb45_we = 0;
                is_45 = 0;
                invalid_data = 0;
                if (!fifo_comb_empty && !fifo_comb45_hfull && fifo_comb_ee && fifo_comb_valid) begin
                    next_state = WRITE_1;
                end
            end
            WRITE_1: begin
                fifo_comb_re = 1;
                fifo_comb45_we = 1;
                hitmux_sel = 3'b000;
                is_45 = 1;
                invalid_data = 0;
                next_state = WRITE_2;
            end
            WRITE_2: begin
                fifo_comb_re = 1;
                fifo_comb45_we = 1;
                hitmux_sel = 3'b001;
                is_45 = 1;
                invalid_data = 0;
                next_state = WRITE_3;
            end
            WRITE_3: begin
                fifo_comb_re = 1;
                fifo_comb45_we = 1;
                hitmux_sel = 3'b010;
                is_45 = 1;
                invalid_data = 0;
                next_state = WRITE_4;
            end
            WRITE_4: begin
                fifo_comb_re = 1;
                fifo_comb45_we = 1;
                hitmux_sel = 3'b011;
                is_45 = 1;
                invalid_data = 0;
                next_state = WRITE_5;
            end
            WRITE_5: begin
                fifo_comb_re = 1;
                fifo_comb45_we = 1;
                hitmux_sel = 3'b100;
                is_45 = 1;
                invalid_data = 0;
                next_state = WAIT;
            end
            default: begin
                fifo_comb_re = 0;
                fifo_comb45_we = 0;
                is_45 = 0;
                invalid_data = 1;
                next_state = WAIT;
            end
        endcase
    end

endmodule

files.origen_145625.v:
module origen_145625 (
    input wire clk,
    input wire reset,
    input wire p1_move,
    input wire p2_move,
    input wire p1_win,
    input wire p2_win,
    input wire tie,
    output reg turno_p1,
    output reg turno_p2,
    output reg win_game,
    output reg loss_game,
    output reg tie_game,
    output reg send_state
);

    // State encoding
    localparam [2:0] 
        P1_MOVE  = 3'b000,
        P1_STATUS = 3'b001,
        P2_MOVE  = 3'b010,
        P2_STATUS = 3'b011,
        WIN     = 3'b100,
        TIE     = 3'b101,
        LOSS    = 3'b110;

    reg [2:0] current_state, next_state;

    // State register
    always @(posedge clk or posedge reset) begin
        if (reset)
            current_state <= P1_MOVE;
        else
            current_state <= next_state;
    end

    // Next state logic
    always @(*) begin
        case (current_state)
            P1_MOVE: next_state = p1_move ? P1_STATUS : P1_MOVE;
            P1_STATUS: begin
                if (p1_win)
                    next_state = WIN;
                else if (tie)
                    next_state = TIE;
                else
                    next_state = P2_MOVE;
            end
            P2_MOVE: next_state = p2_move ? P2_STATUS : P2_MOVE;
            P2_STATUS: begin
                if (p2_win)
                    next_state = LOSS;
                else if (tie)
                    next_state = TIE;
                else
                    next_state = P1_MOVE;
            end
            WIN: next_state = WIN;
            TIE: next_state = TIE;
            LOSS: next_state = LOSS;
            default: next_state = P1_MOVE;
        endcase
    end

    // Output logic
    always @(*) begin
        turno_p1 = 0;
        turno_p2 = 0;
        win_game = 0;
        loss_game = 0;
        tie_game = 0;
        send_state = 0;

        case (current_state)
            P1_MOVE: begin
                turno_p1 = 1;
                send_state = 1;
            end
            P2_MOVE: begin
                turno_p2 = 1;
                send_state = 1;
            end
            WIN: begin
                win_game = 1;
                send_state = 1;
            end
            TIE: begin
                tie_game = 1;
                send_state = 1;
            end
            LOSS: begin
                loss_game = 1;
                send_state = 1;
            end
        endcase
    end

endmodule

