module origen_062861(
    input clk, reset, enable,
    input [3:0] D,
    output reg [3:0] Q
);
    always @(posedge clk) begin
        if (reset)
            Q <= 4'b0000;
        else if (enable)
            Q <= D;
    end
endmodule

module Counter(
    input clk, reset, enable, bitcar,
    input [11:0] L,
    output reg [11:0] E
);
    always @(posedge clk) begin
        if (reset)
            E <= 12'b000000000000;
        else if (enable)
            E <= E + 1;
        else if (bitcar)
            E <= L;
    end
endmodule

module ROM(
    input [11:0] Lect,
    output reg [7:0] Data
);
    reg [7:0] memory [0:4095];

    initial begin
        $readmemh("memory.jmc", memory);
    end

    always @(*) begin
        Data = memory[Lect];
    end
endmodule

module Fetch(
