);
    FFD4 upper_bits(
        .clk(clk),
        .reset(reset),
        .enable(enable2),
        .D(D8[7:4]),
        .Q(Q1)
    );

    FFD4 lower_bits(
        .clk(clk),
        .reset(reset),
        .enable(enable2),
        .D(D8[3:0]),
        .Q(Q2)
    );
endmodule

module Main(
