        .Lect(C),
        .Data(Pb)
    );

    Fetch fetch(
        .clk(clk),
        .reset(reset),
        .enable2(enable2),
        .D8(Pb),
        .Q1(Q1),
        .Q2(Q2)
    );
endmodule
